                writer.WriteString("approvedBy", paymentRefund.ApprovedBy);

            if (paymentRefund.ApprovedAtOption.IsSet)
                writer.WriteString("approvedAt", paymentRefund.ApprovedAtOption.Value!.Value.ToString(ApprovedAtFormat));

            if (paymentRefund.RefundTxOption.IsSet)
                writer.WriteString("refundTx", paymentRefund.RefundTx);

            if (paymentRefund.RefundedAtOption.IsSet)
                writer.WriteString("refundedAt", paymentRefund.RefundedAtOption.Value!.Value.ToString(RefundedAtFormat));

            if (paymentRefund.CreatedAtOption.IsSet)
                writer.WriteString("createdAt", paymentRefund.CreatedAtOption.Value!.Value.ToString(CreatedAtFormat));

            if (paymentRefund.UpdatedAtOption.IsSet)
                writer.WriteString("updatedAt", paymentRefund.UpdatedAtOption.Value!.Value.ToString(UpdatedAtFormat));
        }
    }
}
